{
 "level": "A2",
 "intro": "In this topic, you will learn <strong>the basic rules of forming the passive voice</strong>: the basic formula, how to turn active sentences into passive ones, and when it is appropriate to use the passive voice.",
 "rules": [
 {
 "label": "Formula",
 "color": "emerald",
 "text": "The basic structure of the passive: <strong>Subject + be + V3 (Past Participle)</strong>:",
 "example": "The cake is baked."
 },
 {
 "label": "Transformation",
 "color": "blue",
 "text": "Object of the active sentence → Subject of the passive:",
 "example": "Tom writes letters. → Letters are written by Tom."
 },
 {
 "label": "Performer",
 "color": "rose",
 "text": "<strong>by + agent</strong> — indicates who performs the action:",
 "example": "The book was written by Shakespeare."
 }
 ]
}

{
 "title": "1. Active vs Passive state",
 "intro": "Comparison of active and passive state:",
 "items": [
 {
 "label": "Active",
 "title": "Subject performs the action",
 "subtitle": "Tom writes letters. — Tom is writing to the list."
 },
 {
 "label": "Passive",
 "title": "Subject receives the action",
 "subtitle": "Letters are written by Tom. — Letters are written by Tom."
 },
 {
 "label": "Formula",
 "title": "be + V3",
 "subtitle": "The verb be is in the right tense + Past Participle."
 },
 {
 "label": "Agent",
 "title": "by + performer",
 "subtitle": "It is specified if it is important to know the performer."
 }
 ]
}

{
 "title": "2. How to convert Active → Passive?",
 "sections": [
 {
 "label": "Step 1",
 "color": "emerald",
 "description": "The <strong>Object</strong> of the active sentence becomes the <strong>Subject</strong> of the passive:",
 "examples": [
 {
 "en": "Active: Tom writes letters.",
 "ua": "Active: Tom writes letters."
 },
 {
 "en": "Active: They built a house.",
 "ua": "Active: They built a house."
 }
 ]
 },
 {
 "label": "Step 2",
 "color": "blue",
 "description": "We add <strong>be</strong> in the objectropriate tense + <strong>V3</strong>:",
 "examples": [
 {
 "en": "writes → is/are written",
 "ua": "writes → is/are written"
 },
 {
 "en": "built → was/were built",
 "ua": "built → was/were built"
 }
 ]
 },
 {
 "label": "Step 3",
 "color": "rose",
 "description": "The <strong>Subject</strong> of the active sentence becomes <strong>by + agent</strong> (if necessary):",
 "examples": [
 {
 "en": "Tom → by Tom",
 "ua": "Tom → by Tom"
 },
 {
 "en": "They →",
 "ua": "They →"
 }
 ]
 }
 ]
}

{
 "title": "3. Examples of Active → Passive conversion",
 "intro": "The complete process of converting active sentences into passive:",
 "rows": [
 {
 "en": "Active: Mary bakes a cake.",
 "ua": "Active: Mary bakes a cake.",
 "note": "→ Passive: A cake is baked by Mary."
 },
 {
 "en": "Active: They speak English here.",
 "ua": "Active: They speak English here.",
 "note": "→ Passive: English is spoken here."
 },
 {
 "en": "Active: Someone stole my bike.",
 "ua": "Active: Someone stole my bike.",
 "note": "→ Passive: My bike was stolen."
 },
 {
 "en": "Active: The company will hire new employees.",
 "ua": "Active: The company will hire new employees.",
 "note": "→ Passive: New employees will be hired by the company."
 }
 ],
 "warning": "📌 by + agent is omitted if the artist is unknown, unimportant or obvious!"
}

{
 "title": "4. When to use the passive voice?",
 "sections": [
 {
 "label": "Unknown artist",
 "color": "emerald",
 "description": "When it is <strong>not known</strong> who performed the action:",
 "examples": [
 {
 "en": "My car was stolen last night.",
 "ua": "My car was stolen last night."
 },
 {
 "en": "The window has been broken.",
 "ua": "The window has been broken."
 },
 {
 "en": "The building was destroyed.",
 "ua": "The building was destroyed."
 }
 ]
 },
 {
 "label": "An unimportant performer",
 "color": "blue",
 "description": "When the performer is <strong>unimportant</strong> or obvious:",
 "examples": [
 {
 "en": "The streets are cleaned every day.",
 "ua": "The streets are cleaned every day."
 },
 {
 "en": "Tickets are sold at the entrance.",
 "ua": "Tickets are sold at the entrance."
 },
 {
 "en": "The law was passed last year.",
 "ua": "The law was passed last year."
 }
 ]
 },
 {
 "label": "Focus on action/object",
 "color": "amber",
 "description": "When the <strong>action</strong> or the <strong>object</strong> is more important:",
 "examples": [
 {
 "en": "The report was submitted on time.",
 "ua": "The report was submitted on time."
 },
 {
 "en": "The new system will be launched tomorrow.",
 "ua": "The new system will be launched tomorrow."
 },
 {
 "en": "The product is made in Germany.",
 "ua": "The product is made in Germany."
 }
 ]
 },
 {
 "label": "Formal style",
 "color": "rose",
 "description": "In <strong>scientific, official</strong> and <strong>business</strong> style:",
 "examples": [
 {
 "en": "The experiment was conducted carefully.",
 "ua": "The experiment was conducted carefully."
 },
 {
 "en": "Applicants will be notified by email.",
 "ua": "Applicants will be notified by email."
 },
 {
 "en": "The data is analyzed weekly.",
 "ua": "The data is analyzed weekly."
 }
 ]
 }
 ]
}

{
 "title": "5. By vs With in the passive",
 "intro": "The difference between <strong>by</strong> and <strong>with</strong> in passive sentences:",
 "items": [
 {
 "label": "by",
 "title": "Who performs the action (agent)",
 "subtitle": "The book was written by Mark Twain."
 },
 {
 "label": "with",
 "title": "What/by means of what (instrument)",
 "subtitle": "The letter was written with a pen."
 },
 {
 "label": "by",
 "title": "A living being or organization",
 "subtitle": "The project was completed by our team."
 },
 {
 "label": "with",
 "title": "Tool, material",
 "subtitle": "The cake was decorated with chocolate."
 }
 ]
}

{
 "title": "6. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Omission of the verb be.",
 "wrong": "The letter written yesterday.",
 "right": "✅ The letter was written yesterday."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Using V1/V2 instead of V3.",
 "wrong": "English is speak here.",
 "right": "✅ English is spoken here."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Using with instead of by for executor.",
 "wrong": "The book was written with Shakespeare.",
 "right": "✅ The book was written by Shakespeare."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Extra by agent.",
 "wrong": "My car was stolen by someone.",
 "right": "✅ My car was stolen."
 }
 ]
}
